	defaultCatalogFreshTTL            = 60 * time.Second
	defaultCatalogStaleTTL            = 10 * time.Minute
	defaultCatalogUnreachableCooldown = 30 * time.Second
	defaultCatalogUnreachableJitter   = 5 * time.Second
	defaultCatalogAsyncRefreshTimeout = 30 * time.Second
)

// catalogCacheKey identifies the cache entry. Uses fingerprinted auth so
// different API keys for the same baseURL don't share cached state.
type catalogCacheKey struct {
	BaseURL     string
	APIKeyHash  [sha256.Size]byte
	HeadersHash [sha256.Size]byte
}

// String returns a deterministic key identity suitable for singleflight.
// The hash is already collision-resistant; concatenate the three components
// so the singleflight deduplicates by the full identity, not by baseURL alone.
func (k catalogCacheKey) String() string {
	var b strings.Builder
	b.WriteString(k.BaseURL)
	b.WriteByte('|')
	for _, x := range k.APIKeyHash {
		b.WriteByte(hexDigit(x >> 4))
		b.WriteByte(hexDigit(x & 0x0f))
	}
	b.WriteByte('|')
	for _, x := range k.HeadersHash {
		b.WriteByte(hexDigit(x >> 4))
		b.WriteByte(hexDigit(x & 0x0f))
	}
	return b.String()
}

func hexDigit(b byte) byte {
	if b < 10 {
		return '0' + b
	}
	return 'a' + b - 10
}

// catalogEntry is the per-key cached state. Never exposed to callers without
// deep-copying, so cache mutation is impossible from the outside.
type catalogEntry struct {
	IDs                []string  // last successful discovery (server order)
	FetchedAt          time.Time // zero when never fetched
	LastErr            error     // the most recent error; nil on success
	UnreachableAt      time.Time // zero unless last attempt produced a ReachabilityError
	DiscoverySupported bool      // false when /v1/models returns 404 (passthrough mode)
}

// catalogCache is the service-scope live-catalog cache with stale-while-
// revalidate semantics + unreachable cooldown + cold-miss coalescing via
// singleflight. One instance per service.
type catalogCache struct {
	mu  sync.Mutex
	mem map[catalogCacheKey]*catalogEntry
	sf  singleflight.Group
	// opts is captured at construction; read without mu (immutable).
	opts catalogCacheOptions
}

// catalogCacheOptions controls timings + test hooks. Production uses
// defaults via newCatalogCache().
type catalogCacheOptions struct {
	FreshTTL            time.Duration
	StaleTTL            time.Duration
	UnreachableCooldown time.Duration
	UnreachableJitter   time.Duration
	AsyncRefreshTimeout time.Duration
	Now                 func() time.Time // injectable for tests
	RandInt63n          func(n int64) int64
}

func (o catalogCacheOptions) withDefaults() catalogCacheOptions {
	if o.FreshTTL <= 0 {
		o.FreshTTL = defaultCatalogFreshTTL
	}
	if o.StaleTTL <= 0 {
		o.StaleTTL = defaultCatalogStaleTTL
	}
	if o.UnreachableCooldown <= 0 {
		o.UnreachableCooldown = defaultCatalogUnreachableCooldown
	}
	// UnreachableJitter may legitimately be 0 (tests); don't override.
	if o.AsyncRefreshTimeout <= 0 {
		o.AsyncRefreshTimeout = defaultCatalogAsyncRefreshTimeout
	}
	if o.Now == nil {
		o.Now = time.Now
	}
	if o.RandInt63n == nil {
		o.RandInt63n = cryptoRandInt63n
	}
	return o
}

// cryptoRandInt63n uses crypto/rand for the jitter randomization. Not
// performance-critical — at most one call per unreachable miss.
func cryptoRandInt63n(n int64) int64 {
	if n <= 0 {
		return 0
	}
	r, err := rand.Int(rand.Reader, big.NewInt(n))
	if err != nil {
		// Vanishingly unlikely; fall back to a non-zero bound so we
		// never return the exact cooldown and risk synchronized retries
		// across many goroutines.
		return int64(time.Now().UnixNano()) % n
	}
	return r.Int64()
}

func newCatalogCache(opts catalogCacheOptions) *catalogCache {
	return &catalogCache{
		mem:  make(map[catalogCacheKey]*catalogEntry),
		opts: opts.withDefaults(),
	}
}

// newCatalogCacheKey builds a cache key from endpoint identity. api_key and
// headers are hashed so the key is stable but doesn't carry secrets in the
// map key's string representation.
func newCatalogCacheKey(baseURL, apiKey string, headers map[string]string) catalogCacheKey {
	return catalogCacheKey{
		BaseURL:     baseURL,
		APIKeyHash:  sha256.Sum256([]byte(apiKey)),
		HeadersHash: hashHeaders(headers),
	}
}

// hashHeaders fingerprints a headers map in a deterministic way so ordering
// doesn't affect the hash.
func hashHeaders(headers map[string]string) [sha256.Size]byte {
	if len(headers) == 0 {
		return sha256.Sum256(nil)
	}
	keys := make([]string, 0, len(headers))
	for k := range headers {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	h := sha256.New()
	lenBuf := make([]byte, 8)
	for _, k := range keys {
		v := headers[k]
		binary.BigEndian.PutUint64(lenBuf, uint64(len(k)))
		_, _ = h.Write(lenBuf)
		_, _ = h.Write([]byte(k))
		binary.BigEndian.PutUint64(lenBuf, uint64(len(v)))
		_, _ = h.Write(lenBuf)
		_, _ = h.Write([]byte(v))
	}
	var out [sha256.Size]byte
	copy(out[:], h.Sum(nil))
	return out
}

// CatalogResult is what callers receive from Get. All fields are copies —
// mutating them does not affect cache state.
type CatalogResult struct {
	IDs                []string  // server-order model IDs; empty when discovery unsupported or never fetched successfully
	FetchedAt          time.Time // zero when no successful fetch has occurred
	DiscoverySupported bool      // false when /v1/models returned 404; callers passthrough
	LastErr            error     // last probe's error if any; may be a ReachabilityError
	FromCache          bool      // true when served from cache (fresh or stale)
	Stale              bool      // true when served from a stale cache entry (async refresh kicked)
}

// Get looks up the cache and probes if necessary. Returns a CatalogResult
// plus an error. Semantics:
//
//   - Fresh hit: returns cached IDs + no error. FromCache=true, Stale=false.
//   - Stale hit: returns cached IDs + kicks background refresh via
//     singleflight. FromCache=true, Stale=true.
//   - Unreachable within cooldown: returns the cached ReachabilityError.
//     FromCache=true. No fresh probe attempted.
//   - Cold miss: synchronous probe via singleflight (one probe for N
//     concurrent callers). Populates cache with result.
//
// The CatalogResult is always returned; inspect it even when err is non-nil.
func (c *catalogCache) Get(ctx context.Context, key catalogCacheKey, probe CatalogProbeFunc) (CatalogResult, error) {
	c.mu.Lock()
	e, ok := c.mem[key]
	now := c.opts.Now()
	if ok {
		// Unreachable cooldown active?
		if !e.UnreachableAt.IsZero() {
			cooldown := c.opts.UnreachableCooldown
			if c.opts.UnreachableJitter > 0 {
				cooldown += time.Duration(c.opts.RandInt63n(int64(c.opts.UnreachableJitter)))
			}
			if now.Sub(e.UnreachableAt) < cooldown {
				result := snapshotEntry(e)
				result.FromCache = true
				c.mu.Unlock()
				return result, e.LastErr
			}
		}
		// Fresh?
		if !e.FetchedAt.IsZero() && now.Sub(e.FetchedAt) < c.opts.FreshTTL && e.LastErr == nil {
			result := snapshotEntry(e)
			result.FromCache = true
			c.mu.Unlock()
			return result, nil
		}
		// Stale — within StaleTTL of last successful fetch?
		if !e.FetchedAt.IsZero() && now.Sub(e.FetchedAt) < c.opts.StaleTTL && e.LastErr == nil {
			result := snapshotEntry(e)
			result.FromCache = true
			result.Stale = true
			c.mu.Unlock()
			// Kick async refresh — singleflight coalesces parallel callers.
			parentCtx := context.WithoutCancel(ctx)
			go func() {
				ctx, cancel := context.WithTimeout(parentCtx, c.opts.AsyncRefreshTimeout)
				defer cancel()
				_, _, _ = c.sf.Do(key.String(), func() (interface{}, error) {
					return c.probe(ctx, key, probe)
				})
			}()
			return result, nil
		}
	}
	c.mu.Unlock()

	// Cold miss or beyond StaleTTL or previous failure outside cooldown:
	// synchronous probe via singleflight.
	r, err, _ := c.sf.Do(key.String(), func() (interface{}, error) {
		return c.probe(ctx, key, probe)
	})
	if r == nil {
		return CatalogResult{LastErr: err}, err
	}
	result := r.(CatalogResult)
	return result, err
}

// probe executes the probe, updates the cache, and returns a CatalogResult.
// Runs inside singleflight — one call per key even under concurrent misses.
func (c *catalogCache) probe(ctx context.Context, key catalogCacheKey, probeFn CatalogProbeFunc) (CatalogResult, error) {
	ids, err := probeFn(ctx)
	c.mu.Lock()
	defer c.mu.Unlock()
	now := c.opts.Now()
	e, ok := c.mem[key]
	if !ok {
		e = &catalogEntry{DiscoverySupported: true}
		c.mem[key] = e
	}
	e.LastErr = err
	switch {
	case err == nil:
		// Successful probe.
		e.IDs = append([]string(nil), ids...)
		e.FetchedAt = now
		e.UnreachableAt = time.Time{}
		e.DiscoverySupported = true
	case isDiscoveryUnsupported(err):
		// 404 on /v1/models — endpoint exists but doesn't expose discovery.
		// Fall back to passthrough: callers send their original model string
		// without normalization.
		e.DiscoverySupported = false
		e.UnreachableAt = time.Time{}
		// IDs intentionally left as-is from prior success (if any); most
		// likely empty on fresh endpoints.
	case isReachabilityErr(err):
		// 5xx or network failure — start cooldown.
		e.UnreachableAt = now
	default:
		// Other errors (auth 401/403, unexpected shape). Record but do NOT
		// treat as unreachable. Downstream Chat calls may still succeed
		// if auth works at the chat layer (unusual but possible), or will
		// surface their own errors.
		e.UnreachableAt = time.Time{}
	}
	return snapshotEntry(e), err
}

// snapshotEntry copies entry state for safe return outside the lock.
func snapshotEntry(e *catalogEntry) CatalogResult {
	return CatalogResult{
		IDs:                append([]string(nil), e.IDs...),
		FetchedAt:          e.FetchedAt,
		DiscoverySupported: e.DiscoverySupported,
		LastErr:            e.LastErr,
	}
}

// errDiscoveryUnsupported is the sentinel for "endpoint exists but /v1/models
// returns 404." CatalogProbeFunc implementations return this so the cache
// knows to switch to passthrough.
var errDiscoveryUnsupported = &discoveryUnsupportedError{}

type discoveryUnsupportedError struct{}

func (e *discoveryUnsupportedError) Error() string {
	return "agent: endpoint does not support /v1/models discovery"
}

// ErrDiscoveryUnsupported returns the sentinel. Callers compare via
// errors.Is(err, ErrDiscoveryUnsupported()).
func ErrDiscoveryUnsupported() error { return errDiscoveryUnsupported }

func isDiscoveryUnsupported(err error) bool {
	for e := err; e != nil; {
		if _, ok := e.(*discoveryUnsupportedError); ok {
			return true
		}
		if u, ok := e.(interface{ Unwrap() error }); ok {
			e = u.Unwrap()
			continue
		}
		break
	}
	return false
}

// isReachabilityErr reports whether err carries the openai.ErrEndpointUnreachable
// sentinel. Probe implementations wrap transport/5xx failures as
// *openai.ReachabilityError; this cache uses errors.Is to detect them.
func isReachabilityErr(err error) bool {
	if err == nil {
		return false
	}
	return errors.Is(err, openai.ErrEndpointUnreachable)
}

package fizeau

import (
	"context"
	"errors"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/provider/openai"
	"github.com/easel/fizeau/internal/sdk/openaicompat"
)

// QuotaRecoveryProber reports whether a quota_exhausted provider has recovered.
// A nil error indicates the provider is back online; a non-nil error keeps it
// in quota_exhausted with an extended retry_after.
type QuotaRecoveryProber func(ctx context.Context, provider string) error

const (
	// defaultQuotaRecoveryFallbackInterval is the wake interval used when no
	// quota_exhausted provider has a known retry_after to drive the next probe.
	defaultQuotaRecoveryFallbackInterval = 5 * time.Minute
	// quotaRecoveryBackoffInitial is the first retry_after extension applied
	// after a probe failure when no prior backoff is recorded.
	quotaRecoveryBackoffInitial = 5 * time.Minute
	// quotaRecoveryBackoffMax caps the exponential backoff between failed
	// probes so a persistently-down provider is still re-probed at least
	// once an hour.
	quotaRecoveryBackoffMax = 1 * time.Hour
)

// runQuotaRecoveryProbeLoop periodically probes providers that the store
// reports as quota_exhausted. When a provider's retry_after has elapsed (or
// is unknown) the loop calls probe; on success the provider is moved back to
// available, on failure its retry_after is extended with bounded exponential
// backoff. The loop exits when ctx is cancelled.
//
// fallback bounds the maximum sleep between passes. now/sleep are seams for
// deterministic tests; pass nil for production defaults.
func runQuotaRecoveryProbeLoop(
	ctx context.Context,
	store *ProviderQuotaStateStore,
	probe QuotaRecoveryProber,
	fallback time.Duration,
	now func() time.Time,
	sleep func(ctx context.Context, d time.Duration) bool,
) {
	if ctx == nil || store == nil || probe == nil {
		return
	}
	if fallback <= 0 {
		fallback = defaultQuotaRecoveryFallbackInterval
	}
	if now == nil {
		now = time.Now
	}
	if sleep == nil {
		sleep = quotaRecoverySleep
	}
	backoffs := make(map[string]time.Duration)
	for {
		next := runQuotaRecoveryProbePass(ctx, store, probe, fallback, now, backoffs)
		if !sleep(ctx, next) {
			return
		}
	}
}

// runQuotaRecoveryProbePass executes a single sweep over the quota_exhausted
// set and returns the duration to sleep before the next sweep.
func runQuotaRecoveryProbePass(
	ctx context.Context,
	store *ProviderQuotaStateStore,
	probe QuotaRecoveryProber,
	fallback time.Duration,
	now func() time.Time,
	backoffs map[string]time.Duration,
) time.Duration {
	entries := store.AllExhausted()
	t := now()
	// Drop backoff bookkeeping for providers no longer exhausted (e.g.
	// MarkAvailable was called externally) so a future re-exhaustion starts
	// with a fresh initial backoff.
	for name := range backoffs {
		if _, ok := entries[name]; !ok {
			delete(backoffs, name)
		}
	}
	if len(entries) == 0 {
		return fallback
	}
	nextWake := fallback
	for name, retry := range entries {
		if ctx.Err() != nil {
			return fallback
		}
		if !retry.IsZero() && retry.After(t) {
			if d := retry.Sub(t); d < nextWake {
				nextWake = d
			}
			continue
		}
		if err := probe(ctx, name); err == nil {
			store.MarkAvailable(name)
			delete(backoffs, name)
			continue
		}
		next := nextQuotaRecoveryBackoff(backoffs[name])
		backoffs[name] = next
		newRetry := t.Add(next)
		store.MarkQuotaExhausted(name, newRetry)
		if next < nextWake {
			nextWake = next
		}
	}
	if nextWake <= 0 {
		nextWake = fallback
	}
	return nextWake
}

// nextQuotaRecoveryBackoff returns the next bounded backoff value: doubles the
// previous extension, starting at quotaRecoveryBackoffInitial, capped at
// quotaRecoveryBackoffMax.
func nextQuotaRecoveryBackoff(prev time.Duration) time.Duration {
	if prev <= 0 {
		return quotaRecoveryBackoffInitial
	}
	next := prev * 2
	if next > quotaRecoveryBackoffMax {
		return quotaRecoveryBackoffMax
	}
	return next
}

// quotaRecoverySleep blocks for d or until ctx is cancelled. Returns true if
// the sleep completed normally and false if ctx was cancelled.
func quotaRecoverySleep(ctx context.Context, d time.Duration) bool {
	if d <= 0 {
		return ctx.Err() == nil
	}
	timer := time.NewTimer(d)
	defer timer.Stop()
	select {
	case <-ctx.Done():
		return false
	case <-timer.C:
		return true
	}
}

// probeOpenAIModels calls GET /v1/models against baseURL and classifies
// failures into the three shapes the catalog cache understands:
//
//   - *openai.ReachabilityError for 5xx / transport failures (endpoint
//     unreachable); cache sets an UnreachableCooldown.
//   - errDiscoveryUnsupported for 404 / endpoints that don't expose
//     /v1/models; cache marks DiscoverySupported=false and callers
//     fall back to passthrough model naming.
//   - other errors (401/403 auth, unexpected body) are returned as-is;
//     the cache records them but doesn't mark the endpoint unreachable.
//
// The returned IDs are whatever the server returned in its `data[].id`
// list, preserving server-provided order.
func probeOpenAIModels(ctx context.Context, baseURL, apiKey string) ([]string, error) {
	ids, err := openaicompat.DiscoverModels(ctx, baseURL, apiKey)
	if err == nil {
		return ids, nil
	}
	msg := err.Error()
	// openaicompat.DiscoverModels returns errors prefixed with
	// "HTTP <code>: <body>" for non-2xx responses.
	if strings.Contains(msg, "HTTP 404") {
		return nil, ErrDiscoveryUnsupported()
	}
	if isServerError(msg) || isNetworkFailure(err) {
		return nil, &openai.ReachabilityError{
			Endpoint:   baseURL,
			Operation:  "probe_models",
			StatusCode: extractStatusCode(msg),
			Cause:      err,
		}
	}
	return nil, err
}

// isServerError returns true when the error message indicates a 5xx
// response from the discovery endpoint.
func isServerError(msg string) bool {
	for _, prefix := range []string{"HTTP 500", "HTTP 501", "HTTP 502", "HTTP 503", "HTTP 504", "HTTP 505"} {
		if strings.Contains(msg, prefix) {
			return true
		}
	}
	return false
}

// isNetworkFailure returns true when err looks like a transport-level
// failure (dial, timeout, TLS, connection reset) — the ReachabilityError
// classification applies.
func isNetworkFailure(err error) bool {
	if err == nil {
		return false
	}
	msg := err.Error()
	markers := []string{
		"connection refused",
		"connection reset",
		"no such host",
		"tls: handshake",
		"TLS handshake",
		"i/o timeout",
		"dial tcp",
		"broken pipe",
	}
	for _, m := range markers {
		if strings.Contains(msg, m) {
			return true
		}
	}
	// Explicitly NOT classifying context.DeadlineExceeded as network —
	// that's the caller's own deadline.
	return errors.Is(err, errDialishNetworkError)
}

// extractStatusCode pulls the status code out of the "HTTP NNN:" prefix
// used by openaicompat.DiscoverModels. Returns 0 when no code is found.
func extractStatusCode(msg string) int {
	const prefix = "HTTP "
	idx := strings.Index(msg, prefix)
	if idx < 0 {
		return 0
	}
	tail := msg[idx+len(prefix):]
	if len(tail) < 3 {
		return 0
	}
	code := 0
	for i := 0; i < 3 && i < len(tail); i++ {
		c := tail[i]
		if c < '0' || c > '9' {
			return 0
		}
		code = code*10 + int(c-'0')
	}
	return code
}

// errDialishNetworkError is a sentinel for errors.Is tests. Callers may
// wrap their own network errors with this to ensure isNetworkFailure
// picks them up even when the message doesn't match one of the literal
// markers.
var errDialishNetworkError = errors.New("agent: network failure")

package fizeau

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"strings"
	"sync/atomic"
	"time"

	"github.com/easel/fizeau/internal/compaction"
	agentcore "github.com/easel/fizeau/internal/core"
	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/reasoning"
	"github.com/easel/fizeau/internal/routing"
	"github.com/easel/fizeau/internal/serviceimpl"
	"github.com/easel/fizeau/internal/tool"
)

// generateSessionID returns a unique session identifier for a new Execute.
func generateSessionID() string {
	return fmt.Sprintf("svc-%d", time.Now().UnixNano())
}

// Execute runs an agent task in-process; emits Events on the returned
// channel until the task terminates (channel closes). The final event
// (type=final) carries status, usage, cost, session-log path, and the
// resolved fallback chain that fired.
//
// See CONTRACT-003 §"Behaviors the contract guarantees" for the full
// behavior contract this method honors:
//   - Orphan-model validation (Status=failed when Model unknown)
//   - Provider-deadline wrapping (Timeout + IdleTimeout + ProviderTimeout)
//   - StallPolicy enforcement (stall event before final)
//   - Route-reason attribution (routing_decision start, routing_actual final)
//   - OS-level subprocess cleanup on ctx.Done()
//   - Metadata bidirectional echo (events + session log)
//   - SessionLogDir per-request override
//
// Routing: under-specified requests (no Harness) are dispatched through
// internal/routing.Resolve via ResolveRoute. Callers can run with bare
// Policy/Model/Provider — the engine picks. NativeProvider must
// still be supplied for the native path until provider construction lands
// in a follow-up.
func (s *service) Execute(ctx context.Context, req ServiceExecuteRequest) (<-chan ServiceEvent, error) {
	// Boundary validation: reject unknown CachePolicy values before any
	// session state is opened or events are emitted. Beads C/D consume this
	// field; an unknown value is a caller programming error.
	if err := ValidateCachePolicy(req.CachePolicy); err != nil {
		return nil, err
	}
	if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
		return nil, err
	}
	if err := ValidateRole(req.Role); err != nil {
		return nil, err
	}
	if err := ValidateCorrelationID(req.CorrelationID); err != nil {
		return nil, err
	}

	// Generate a session ID and register it in the hub so TailSessionLog
	// callers can subscribe before or during execution.
	sessionID := generateSessionID()
	fanout := s.executeEventFanout()
	fanout.OpenSession(sessionID)

	outer := make(chan ServiceEvent, 64)

	// ADR-006 §3/§4: capture the override context (user pin + unconstrained
	// auto decision) before route resolution so we can fire the matching
	// override / rejected_override event regardless of which path the route
	// resolution takes.
	overrideCtx := s.buildOverrideContext(ctx, req)

	// ADR-006 §5: record this request into the routing-quality store so
	// auto_acceptance_rate / override_disagreement_rate / class_breakdown
	// reflect both overridden and non-overridden traffic. The recorded
	// override payload carries no outcome — outcome aggregation for live
	// requests is best-effort and lives in session logs once that
	// persistence path lands.
	s.recordRoutingQualityForRequest(overrideCtx)

	// Resolve the route.
	decision, err := s.executeRouteResolver().resolveExecuteRouteContext(ctx, req)
	if err != nil {
		// NoViableProviderForNow is a transient quota signal — DDx
		// callers pause their drain loop on RetryAfter and resume.
		// Surface it directly (not via the fatal-final channel) so the
		// typed error reaches errors.As without log scraping.
		var quotaErr *NoViableProviderForNow
		if errors.As(err, &quotaErr) {
			fanout.CloseSession(sessionID, ServiceEvent{})
			return nil, err
		}
		if isExplicitPinError(err) {
			// Emit a rejected_override event (no outcome) when the pin
			// fails pre-dispatch. Surface the typed error wrapped with
			// the rejected_override payload so callers that errors.As
			// the typed pin error still get it; callers wanting the
			// telemetry can extract via AsRejectedOverride.
			pinErr := err
			if overrideCtx != nil {
				if rejectedEv, payload, ok := makeRejectedOverrideEvent(overrideCtx, sessionID, pinErr, req.Metadata); ok {
					fanout.BroadcastEvent(sessionID, rejectedEv)
					// Persist the rejected_override to the session log so
					// UsageReport's windowed scan (which sources from
					// session logs, not the in-memory ring) sees this
					// rejection. The pin failed pre-dispatch, so no
					// runExecute will open a log for this session — open
					// one briefly here, write session.start + the rejected
					// payload, and close.
					s.persistRejectedOverride(req, sessionID, payload)
					pinErr = &ErrRejectedOverride{Inner: err, Event: payload}
				}
			}
			fanout.CloseSession(sessionID, ServiceEvent{})
			return nil, pinErr
		}
		// Still return a channel that yields a single failed final event so
		// downstream consumers don't have to special-case the error path.
		// Also close the hub session so TailSessionLog subscribers unblock.
		go func() {
			emitFatalFinal(outer, req.Metadata, "failed", err.Error())
			// Drain outer to get the final event and forward to hub.
			// emitFatalFinal closes outer; read the single event from it.
		}()
		// We can't easily intercept emitFatalFinal here, so close the hub
		// session with an empty final immediately — callers on TailSessionLog
		// for a failed-route session get an empty close.
		go func() {
			// Wait briefly for emitFatalFinal to write.
			time.Sleep(10 * time.Millisecond)
			fanout.CloseSession(sessionID, ServiceEvent{})
		}()
		return outer, nil
	}

	// Metadata seam: every event we emit echoes req.Metadata.
	meta := req.Metadata

	// Wrap the inner channel through the hub so every event is broadcast to
	// TailSessionLog subscribers. The fan-out goroutine owns outer's close
	// and is responsible for inserting the override event (if any) immediately
	// before the final event per ADR-006 §7.
	inner := wrapExecuteWithHub(fanout, sessionID, outer, overrideCtx, meta)

	// Emit start-of-execution routing_decision so consumers know the picked
	// chain before any real work fires. The actual chain (post-fallback) is
	// stamped onto the final event's RoutingActual field.
	go s.runExecute(ctx, req, *decision, meta, inner, sessionID, overrideCtx)
	return outer, nil
}

// resolveExecuteRoute reduces the request to a concrete RouteDecision.
// The request is dispatched through the routing engine
// (internal/routing.Resolve) when under-specified (Harness == ""), or when
// Harness is set but Model is empty and routing inputs (Policy or MinPower)
// are present (engine runs within the harness's eligible models). When Harness
// is set and Model is also set, the decision is accepted verbatim.
func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
	return s.resolveExecuteRouteContext(context.Background(), req)
}

func (s *service) resolveExecuteRouteContext(ctx context.Context, req ServiceExecuteRequest) (*RouteDecision, error) {
	// If Harness is omitted, route through the engine. The engine defaults to
	// local-first and auto-selects from configured endpoints when no other
	// constraints are specified — an empty request is valid if providers exist.
	if req.Harness == "" {
		return s.resolveExecuteRouteWithEngine(ctx, req)
	}
	canonical := harnesses.ResolveHarnessAlias(req.Harness)
	if !s.registry.Has(canonical) {
		return nil, fmt.Errorf("unknown harness %q", req.Harness)
	}
	cfg, _ := s.registry.Get(canonical)

	// Run per-field validators first so callers get the most specific error.
	// Empty-model routing checks run after these, right before model resolution.
	if err := validateExplicitHarnessPolicy(canonical, cfg, req.Policy); err != nil {
		return nil, err
	}
	if err := validateExplicitProvider(s.opts.ServiceConfig, cfg, req.Provider); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessReasoning(canonical, cfg, req.Reasoning); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessQuota(canonical, cfg); err != nil {
		return nil, err
	}

	// Empty-model routing: only applies to subprocess harnesses with concrete
	// model semantics. TestOnly (virtual/script), HTTP-provider (openrouter/
	// lmstudio/etc.), and "fiz" harnesses skip this block — they either use
	// DefaultModel directly or have provider-side model semantics.
	if !cfg.TestOnly && !cfg.IsHTTPProvider && canonical != "fiz" && req.Model == "" {
		if req.Policy == "" && req.MinPower == 0 {
			// Under-specified: no model, no routing inputs → silent empty model
			// avoided by failing early with a clear diagnostic.
			return nil, fmt.Errorf("under-specified routing for harness=%q: "+
				"supply --model, --policy, or --min-power", canonical)
		}
		// Policy or MinPower present: run the routing engine within the
		// harness's eligible models. Class 2 harnesses (AutoRoutingEligible=false:
		// gemini, opencode, pi) require an explicit --model.
		if !cfg.AutoRoutingEligible {
			return nil, fmt.Errorf("no auto-resolution available for harness=%q: "+
				"harness does not support auto-routing; supply an explicit --model", canonical)
		}
		return s.resolveExecuteRouteWithEngine(ctx, req)
	}

	resolvedModel := resolveSubprocessModelAlias(canonical, req.Model)
	decision := &RouteDecision{
		Harness:  canonical,
		Provider: req.Provider,
		Model:    resolvedModel,
		Reason:   "explicit",
		Power:    catalogPowerForModel(serviceRoutingCatalog(), resolvedModel),
	}
	if decision.Endpoint == "" {
		_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
		decision.Endpoint = endpoint
	}
	return decision, nil
}

func validateExplicitHarnessQuota(name string, cfg harnesses.HarnessConfig) error {
	if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelSubscription {
		return nil
	}
	now := time.Now()
	qs, ok := subscriptionQuotaForHarness(name, now)
	if !ok || !qs.Present || !qs.Fresh || qs.OK {
		return nil
	}
	return explicitQuotaUnavailable(name, qs.Windows, now)
}

func explicitQuotaUnavailable(name string, windows []harnesses.QuotaWindow, now time.Time) error {
	retryAfter := earliestQuotaResetAfter(windows, now)
	if retryAfter.IsZero() {
		retryAfter = now.Add(defaultQuotaRecoveryFallbackInterval)
	}
	return &NoViableProviderForNow{
		RetryAfter:         retryAfter,
		ExhaustedProviders: []string{name},
	}
}

func earliestQuotaResetAfter(windows []harnesses.QuotaWindow, now time.Time) time.Time {
	var earliest time.Time
	for _, window := range windows {
		if window.ResetsAtUnix <= 0 {
			continue
		}
		reset := time.Unix(window.ResetsAtUnix, 0)
		if !reset.After(now) {
			continue
		}
		if earliest.IsZero() || reset.Before(earliest) {
			earliest = reset
		}
	}
	return earliest
}

func validateExplicitHarnessPolicy(name string, cfg harnesses.HarnessConfig, policy string) error {
	constraint, ok := explicitPolicyConstraint(policy)
	if !ok {
		return nil
	}
	switch constraint {
	case routing.ProviderPreferenceLocalOnly:
		if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelFixed {
			return &ErrPolicyRequirementUnsatisfied{
				Policy:       policy,
				Requirement:  constraint,
				AttemptedPin: "Harness=" + name,
			}
		}
	case routing.ProviderPreferenceSubscriptionOnly:
		if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelSubscription {
			return &ErrPolicyRequirementUnsatisfied{
				Policy:       policy,
				Requirement:  constraint,
				AttemptedPin: "Harness=" + name,
			}
		}
	}
	return nil
}

func explicitPolicyConstraint(policy string) (string, bool) {
	switch policy {
	case "air-gapped":
		return routing.ProviderPreferenceLocalOnly, true
	case "smart":
		return routing.ProviderPreferenceSubscriptionOnly, true
	default:
		return "", false
	}
}

func isExplicitPinError(err error) bool {
	var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
	if errors.As(err, &modelConstraintAmbiguous) {
		return true
	}
	var modelConstraintNoMatch *ErrModelConstraintNoMatch
	if errors.As(err, &modelConstraintNoMatch) {
		return true
	}
	var modelErr *ErrHarnessModelIncompatible
	if errors.As(err, &modelErr) {
		return true
	}
	var policyErr *ErrPolicyRequirementUnsatisfied
	if errors.As(err, &policyErr) && policyErr.AttemptedPin != "" {
		return true
	}
	var pinErr *ErrUnsatisfiablePin
	if errors.As(err, &pinErr) {
		return true
	}
	var providerErr *ErrUnknownProvider
	return errors.As(err, &providerErr)
}

// validateExplicitProvider rejects pre-dispatch when the caller pinned a
// provider name that the service configuration does not recognize. Returns
// nil when no provider was pinned, when no ServiceConfig is configured (no
// provider catalog to validate against), when the provider name is known,
// or when the harness is test-only / does not consume Provider (virtual,
// script, etc. have no real provider lookup).
func validateExplicitProvider(sc ServiceConfig, cfg harnesses.HarnessConfig, provider string) error {
	if provider == "" || sc == nil {
		return nil
	}
	if cfg.TestOnly {
		return nil
	}
	lookup := provider
	if base, _, ok := splitEndpointProviderRef(provider); ok {
		lookup = base
	}
	if _, ok := sc.Provider(lookup); ok {
		return nil
	}
	known := sc.ProviderNames()
	return &ErrUnknownProvider{Provider: provider, KnownProviders: append([]string(nil), known...)}
}

func validateExplicitHarnessModel(name string, cfg harnesses.HarnessConfig, model, provider string) error {
	if model == "" || cfg.TestOnly || cfg.IsHTTPProvider || name == "fiz" {
		return nil
	}
	if modelSupportedForHarness(name, cfg, model, provider) {
		return nil
	}
	supportedModels := subprocessHarnessModelIDs(name, cfg)
	return &ErrHarnessModelIncompatible{
		Harness:         name,
		Model:           model,
		SupportedModels: append([]string(nil), supportedModels...),
	}
}

func modelSupportedForHarness(name string, cfg harnesses.HarnessConfig, model, provider string) bool {
	for _, known := range subprocessHarnessModelIDs(name, cfg) {
		if model == known {
			return true
		}
	}
	switch name {
	case "codex":
		return strings.HasPrefix(model, "gpt-")
	case "claude":
		return strings.HasPrefix(model, "claude-")
	case "pi":
		// Pi can route to non-Gemini backends (lmstudio, omlx, etc.) when a
		// provider is pinned. The pi CLI owns per-provider model validation
		// in that case, so the agent-side gate trusts the provider pin and
		// defers concrete model-ID checks to pi --list-models / pi itself.
		return provider != ""
	case "opencode":
		// OpenCode can route to configured provider/model pairs when the
		// provider is pinned; the generated opencode config and CLI own the
		// concrete model validation in that case.
		return provider != ""
	default:
		return len(cfg.Models) == 0
	}
}

func (s *service) validateEngineResolvedExecuteDecision(req ServiceExecuteRequest, decision *RouteDecision) error {
	if decision == nil || strings.TrimSpace(req.Harness) == "" || strings.TrimSpace(req.Model) != "" {
		return nil
	}
	canonical := harnesses.ResolveHarnessAlias(req.Harness)
	if decision.Harness != "" && decision.Harness != canonical {
		return &ErrUnsatisfiablePin{
			Pin:    "harness=" + canonical,
			Reason: "routing engine returned a different harness",
		}
	}
	cfg, ok := s.registry.Get(canonical)
	if !ok {
		return fmt.Errorf("unknown harness %q", req.Harness)
	}
	normalizedModel := resolveSubprocessModelAlias(canonical, decision.Model)
	if err := validateExplicitHarnessModel(canonical, cfg, normalizedModel, decision.Provider); err != nil {
		return err
	}
	decision.Harness = canonical
	decision.Model = normalizedModel
	if decision.Endpoint == "" {
		_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
		decision.Endpoint = endpoint
	}
	return nil
}

func validateExplicitHarnessReasoning(name string, cfg harnesses.HarnessConfig, value Reasoning) error {
	if cfg.TestOnly {
		return nil
	}
	if len(cfg.ReasoningLevels) == 0 && cfg.MaxReasoningTokens <= 0 {
		return nil
	}
	policy, err := reasoning.ParseString(string(value))
	if err != nil {
		return fmt.Errorf("unsupported reasoning %q for harness %q: %w", value, name, err)
	}
	switch policy.Kind {
	case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
		return nil
	case reasoning.KindTokens:
		if cfg.MaxReasoningTokens <= 0 {
			return fmt.Errorf("unsupported reasoning %q for harness %q; token budgets are not supported", value, name)
		}
		if policy.Tokens > cfg.MaxReasoningTokens {
			return fmt.Errorf("unsupported reasoning %q for harness %q; max token budget is %d", value, name, cfg.MaxReasoningTokens)
		}
		return nil
	case reasoning.KindNamed:
		for _, supported := range cfg.ReasoningLevels {
			if string(policy.Value) == supported {
				return nil
			}
		}
		return fmt.Errorf("unsupported reasoning %q for harness %q; supported reasoning: %s", value, name, strings.Join(cfg.ReasoningLevels, ", "))
	default:
		return fmt.Errorf("unsupported reasoning %q for harness %q", value, name)
	}
}

func harnessSource(req ServiceExecuteRequest) string {
	if strings.TrimSpace(req.Harness) != "" {
		return "request_harness"
	}
	return "auto_route"
}

// runExecute is the per-Execute goroutine. It owns the channel close path
// and the final event emit. All termination paths funnel through emitFinal
// so the channel always sees a final event before close.
func (s *service) runExecute(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, sessionID string, overrideCtx *overrideContext) {
	defer close(out)

	start := time.Now()
	var seq atomic.Int64

	// Open the service-owned session log writer and guarantee a terminal
	// session.end record plus a clean file close even on unexpected exits.
	// CONTRACT-003 makes session-log lifecycle a service responsibility; the
	// per-path finalizeAndEmit calls below feed writeEnd in lock-step with
	// the public final event.
	sl := s.executeSessionLogOpener().openSessionLog(req, decision, sessionID)
	if overrideCtx != nil {
		sl.override = overrideCtx
	}
	defer func() {
		if !sl.endWritten() {
			sl.writeEnd(req, meta, harnesses.FinalData{
				Status:     "cancelled",
				Error:      "session ended without final event",
				DurationMS: time.Since(start).Milliseconds(),
				RoutingActual: &harnesses.RoutingActual{
					Harness:  decision.Harness,
					Provider: decision.Provider,
					Model:    decision.Model,
				},
			})
		}
		sl.close()
	}()

	// Wall-clock cap.
	runCtx := ctx
	if req.Timeout > 0 {
		var cancel context.CancelFunc
		runCtx, cancel = context.WithTimeout(ctx, req.Timeout)
		defer cancel()
	}

	// Emit routing_decision start event. Include session_id so callers can
	// extract it and pass to TailSessionLog. Per CONTRACT-003 the
	// top-level Role + CorrelationID are echoed into routing_decision
	// event Metadata (top-level wins over caller Metadata for these
	// reserved keys).
	routingMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
	emitJSON(out, &seq, harnesses.EventTypeRoutingDecision, routingMeta, serviceRoutingDecisionDataFromDecision(req, decision, sessionID))
	emitProgress(out, &seq, sl, sessionID, meta, routeProgressData(decision))

	s.executeRunnerInvoker().dispatchExecuteRun(runCtx, executeRunContext{
		req:      req,
		decision: decision,
		meta:     meta,
		out:      out,
		seq:      &seq,
		start:    start,
		sl:       sl,
		session:  sessionID,
	})
}

func (s *service) runVirtual(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
	progress := newSubprocessProgressState(req)
	emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
	result := serviceimpl.RunVirtual(ctx, executeRunnerRequest(req, decision, meta, start))
	final := result.Final
	if result.EmitText {
		emitJSONRaw(out, seq, harnesses.EventTypeTextDelta, meta, harnesses.TextDeltaData{Text: result.Text})
	}
	if progressFinal := progress.noteResponseComplete(final); progressFinal != nil {
		emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
	}
	s.recordRouteAttemptFromFinal(final)
	finalizeAndEmit(out, seq, meta, req, sl, final)
}

func (s *service) runScript(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
	progress := newSubprocessProgressState(req)
	emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
	result := serviceimpl.RunScript(ctx, executeRunnerRequest(req, decision, meta, start))
	final := result.Final
	if result.EmitText {
		emitJSONRaw(out, seq, harnesses.EventTypeTextDelta, meta, harnesses.TextDeltaData{Text: result.Text})
	}
	if progressFinal := progress.noteResponseComplete(final); progressFinal != nil {
		emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
	}
	s.recordRouteAttemptFromFinal(final)
	finalizeAndEmit(out, seq, meta, req, sl, final)
}

func executeRunnerRequest(req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, start time.Time) serviceimpl.ExecuteRunnerRequest {
	return serviceimpl.ExecuteRunnerRequest{
		Prompt:   req.Prompt,
		Metadata: meta,
		Decision: serviceimpl.ExecuteRunnerDecision{
			Harness:        decision.Harness,
			Provider:       decision.Provider,
			ServerInstance: decision.ServerInstance,
			Model:          decision.Model,
		},
		Started: start,
	}
}

func nativeToolsForRequest(req ServiceExecuteRequest) []agentcore.Tool {
	if req.Tools != nil {
		return req.Tools
	}
	return tool.BuiltinToolsForPreset(req.WorkDir, req.ToolPreset, tool.BashOutputFilterConfig{})
}

// runNative drives the in-process agent loop (loop.go's Run). The provider
// is wrapped so per-HTTP timeouts fire independently of the request wall-clock
// cap.
func (s *service) runNative(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
	progress := newNativeProgressState()
	observeAgentEvent := func(ev agentcore.Event) {
		sl.writeEvent(ev)
		switch ev.Type {
		case agentcore.EventLLMRequest:
			var payload nativeLLMRequestPayload
			if err := json.Unmarshal(ev.Data, &payload); err == nil {
				emitProgress(out, seq, sl, sessionID, meta, progress.noteRequest(payload))
			}
		case agentcore.EventLLMResponse:
			var payload nativeLLMResponsePayload
			if err := json.Unmarshal(ev.Data, &payload); err == nil {
				emitProgress(out, seq, sl, sessionID, meta, progress.noteResponse(payload))
			}
		case agentcore.EventToolCall:
			var payload nativeToolCallPayload
			_ = json.Unmarshal(ev.Data, &payload)
			toolName := payload.Tool
			input := payload.Input
			if input == nil {
				if rawIn, err := json.Marshal(map[string]any{"tool": toolName}); err == nil {
					input = rawIn
				}
			}
			callID := fmt.Sprintf("call-%d", ev.Seq)
			_, completeProgress := progress.noteToolCall(callID, payload)
			emitJSONRaw(out, seq, harnesses.EventTypeToolCall, meta, harnesses.ToolCallData{
				ID:    callID,
				Name:  toolName,
				Input: input,
			})
			emitJSONRaw(out, seq, harnesses.EventTypeToolResult, meta, harnesses.ToolResultData{
				ID:         callID,
				Output:     payload.Output,
				Error:      payload.Error,
				DurationMS: payload.DurationMS,
			})
			emitProgress(out, seq, sl, sessionID, meta, completeProgress)
		case agentcore.EventCompactionEnd:
			var payload nativeCompactionPayload
			_ = json.Unmarshal(ev.Data, &payload)
			emitJSONRaw(out, seq, harnesses.EventTypeCompaction, meta, map[string]any{
				"messages_before": payload.MessagesBefore,
				"messages_after":  payload.MessagesAfter,
				"tokens_freed":    payload.TokensBefore - payload.TokensAfter,
			})
			compactionProgress, contextProgress := progress.noteCompaction(payload)
			emitProgress(out, seq, sl, sessionID, meta, compactionProgress)
			emitProgress(out, seq, sl, sessionID, meta, contextProgress)
		}
	}

	var stallMaxReadOnlyIterations *int
	if req.StallPolicy != nil {
		stallMaxReadOnlyIterations = &req.StallPolicy.MaxReadOnlyToolIterations
	}
	serviceimpl.RunNative(ctx, serviceimpl.NativeRequest{
		Prompt:                    req.Prompt,
		SystemPrompt:              req.SystemPrompt,
		Model:                     req.Model,
		Provider:                  req.Provider,
		Harness:                   req.Harness,
		WorkDir:                   req.WorkDir,
		Temperature:               req.Temperature,
		TopP:                      req.TopP,
		TopK:                      req.TopK,
		MinP:                      req.MinP,
		RepetitionPenalty:         req.RepetitionPenalty,
		Seed:                      req.Seed,
		SamplingSource:            req.SamplingSource,
		Reasoning:                 effectiveReasoning(req.Reasoning),
		NoStream:                  req.NoStream,
		Permissions:               req.Permissions,
		Tools:                     nativeToolsForRequest(req),
		ToolPreset:                req.ToolPreset,
		PlanningMode:              req.PlanningMode,
		MaxIterations:             req.MaxIterations,
		MaxTokens:                 req.MaxTokens,
		ReasoningByteLimit:        req.ReasoningByteLimit,
		ProviderTimeout:           req.ProviderTimeout,
		Timeout:                   req.Timeout,
		CachePolicy:               req.CachePolicy,
		CostCapUSD:                req.CostCapUSD,
		StallMaxReadOnlyIteration: stallMaxReadOnlyIterations,
		Metadata:                  meta,
		Decision:                  nativeDecision(decision),
		Started:                   start,
		SessionID:                 sessionID,
	}, serviceimpl.NativeCallbacks{
		ResolveProvider: func(nreq serviceimpl.NativeProviderRequest) serviceimpl.NativeProviderResolution {
			resolved := s.resolveNativeProvider(ServiceExecuteRequest{
				Provider: nreq.Provider,
				Harness:  nreq.Harness,
				Model:    nreq.Model,
			})
			return serviceimpl.NativeProviderResolution{
				Provider: resolved.Provider,
				Name:     resolved.Name,
				Model:    resolved.Entry.Model,
			}
		},
		ProviderNotConfiguredError: func(nreq serviceimpl.NativeProviderRequest, ndecision serviceimpl.NativeDecision) string {
			return s.nativeProviderNotConfiguredError(ServiceExecuteRequest{
				Provider: nreq.Provider,
				Harness:  nreq.Harness,
				Model:    nreq.Model,
			}, routeDecision(ndecision))
		},
		Compactor: func(model string) agentcore.Compactor {
			return newServiceCompactor(req, model)
		},
		ObserveAgentEvent: observeAgentEvent,
		EmitEvent: func(t harnesses.EventType, payload any) {
			emitJSONRaw(out, seq, t, meta, payload)
		},
		BeforeFinal: func(final harnesses.FinalData) {
			if progressFinal := progress.noteFinal(final); progressFinal != nil {
				emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
			}
		},
		Finalize: func(final harnesses.FinalData) {
			s.recordRouteAttemptFromFinal(final)
			finalizeAndEmit(out, seq, meta, req, sl, final)
		},
		ToolWiringHook:          s.toolWiringHook(),
		PromptAssertionHook:     s.promptAssertionHook(),
		CompactionAssertionHook: s.compactionAssertionHook(),
		ObserveTokenUsage:       s.observeTokenUsage,
	})
}

func nativeDecision(decision RouteDecision) serviceimpl.NativeDecision {
	return serviceimpl.NativeDecision{
		Harness:        decision.Harness,
		Provider:       decision.Provider,
		ServerInstance: decision.ServerInstance,
		Model:          decision.Model,
		Candidates:     nativeRouteCandidates(decision.Candidates),
	}
}

func routeDecision(decision serviceimpl.NativeDecision) RouteDecision {
	return RouteDecision{
		Harness:        decision.Harness,
		Provider:       decision.Provider,
		ServerInstance: decision.ServerInstance,
		Model:          decision.Model,
	}
}

func nativeRouteCandidates(in []RouteCandidate) []serviceimpl.NativeRouteCandidate {
	if len(in) == 0 {
		return nil
	}
	out := make([]serviceimpl.NativeRouteCandidate, len(in))
	for i, candidate := range in {
		out[i] = serviceimpl.NativeRouteCandidate{
			Provider:       candidate.Provider,
			Endpoint:       candidate.Endpoint,
			ServerInstance: candidate.ServerInstance,
			Model:          candidate.Model,
			Eligible:       candidate.Eligible,
		}
	}
	return out
}

func newServiceCompactor(req ServiceExecuteRequest, model string) agentcore.Compactor {
	cfg := compaction.DefaultConfig()
	if req.CompactionContextWindow > 0 {
		cfg.ContextWindow = req.CompactionContextWindow
		if cfg.ReserveTokens >= cfg.ContextWindow {
			cfg.ReserveTokens = 0
		}
		if cfg.KeepRecentTokens > cfg.ContextWindow {
			cfg.KeepRecentTokens = cfg.ContextWindow / 2
		}
	}
	if req.CompactionReserveTokens > 0 {
		cfg.ReserveTokens = req.CompactionReserveTokens
	}
	if catalog, err := modelcatalog.Default(); err == nil && catalog != nil && model != "" && req.CompactionContextWindow <= 0 {
		if contextWindow := catalog.ContextWindowForModel(model); contextWindow > 0 {
			cfg.ContextWindow = contextWindow
		}
	}
	return compaction.NewCompactor(cfg)
}

// runSubprocess delegates to a Runner under internal/harnesses/<name>. It
// re-uses the wall-clock-bounded ctx so PTY/orphan reaping is automatic
// when our ctx (which already carries the request Timeout) cancels.
func (s *service) runSubprocess(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string, runner harnesses.Harness) {
	progress := newSubprocessProgressState(req)
	serviceimpl.RunSubprocess(ctx, serviceimpl.SubprocessRequest{
		Prompt:        req.Prompt,
		SystemPrompt:  req.SystemPrompt,
		WorkDir:       req.WorkDir,
		Permissions:   req.Permissions,
		Temperature:   req.Temperature,
		Seed:          req.Seed,
		Reasoning:     effectiveReasoning(req.Reasoning),
		Timeout:       req.Timeout,
		IdleTimeout:   req.IdleTimeout,
		SessionLogDir: req.SessionLogDir,
		Metadata:      meta,
		Decision: serviceimpl.ExecuteRunnerDecision{
			Harness:  decision.Harness,
			Provider: decision.Provider,
			Model:    decision.Model,
		},
		Started:        start,
		SessionLogPath: sessionLogPath(sl),
	}, runner, serviceimpl.SubprocessCallbacks{
		BeforeExecute: func() {
			emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
		},
		BeforeFinal: func(final harnesses.FinalData) {
		},
		ObserveEvent: func(ev harnesses.Event) harnesses.Event {
			ev = progress.annotateToolResultDuration(ev)
			if payload, ok := progress.noteEvent(ev); ok && ev.Type != harnesses.EventTypeProgress {
				emitProgress(out, seq, sl, sessionID, meta, payload)
			}
			if ev.Type == harnesses.EventTypeFinal {
				if payload, ok := progress.noteFinal(ev); ok {
					emitProgress(out, seq, sl, sessionID, meta, payload)
				}
			}
			return ev
		},
		EmitEvent: func(ev harnesses.Event) bool {
			ev.Sequence = seq.Add(1) - 1
			select {
			case out <- ev:
				return true
			case <-ctx.Done():
				return false
			}
		},
		Finalize: func(final harnesses.FinalData) {
			s.recordRouteAttemptFromFinal(final)
			finalizeAndEmit(out, seq, meta, req, sl, final)
		},
		WriteEnd: func(finalMeta map[string]string, final harnesses.FinalData) {
			sl.writeEnd(req, finalMeta, final)
		},
	})
}

func sessionLogPath(sl *serviceSessionLog) string {
	if sl == nil {
		return ""
	}
	return sl.path
}

// emitFinal wraps a FinalData into a ServiceEvent and writes it to out.
// The channel close happens in the caller via defer; this only writes the
// terminator event.
func emitFinal(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, final harnesses.FinalData) {
	raw, err := json.Marshal(final)
	if err != nil {
		raw = []byte(`{"status":"failed","error":"marshal final"}`)
	}
	ev := harnesses.Event{
		Type:     harnesses.EventTypeFinal,
		Sequence: seq.Add(1) - 1,
		Time:     time.Now().UTC(),
		Metadata: meta,
		Data:     raw,
	}
	select {
	case out <- ev:
	case <-time.After(time.Second):
	}
}

// emitFatalFinal is used when Execute itself can't construct a route. It
// writes a single failed final event then closes the channel — used for
// the "no consumer goroutine" path so we still satisfy the channel
// contract.
func emitFatalFinal(out chan<- ServiceEvent, meta map[string]string, status, errMsg string) {
	defer close(out)
	final := harnesses.FinalData{Status: status, Error: errMsg}
	raw, _ := json.Marshal(final)
	ev := harnesses.Event{
		Type:     harnesses.EventTypeFinal,
		Sequence: 0,
		Time:     time.Now().UTC(),
		Metadata: meta,
		Data:     raw,
	}
	select {
	case out <- ev:
	case <-time.After(time.Second):
	}
}

// emitJSON marshals payload and writes a typed event to out.
func emitJSON(out chan<- ServiceEvent, seq *atomic.Int64, t harnesses.EventType, meta map[string]string, payload any) {
	raw, err := json.Marshal(payload)
	if err != nil {
		return
	}
	ev := harnesses.Event{
		Type:     t,
		Sequence: seq.Add(1) - 1,
		Time:     time.Now().UTC(),
		Metadata: meta,
		Data:     raw,
	}
	select {
	case out <- ev:
	case <-time.After(time.Second):
	}
}

// emitJSONRaw is the typed-payload variant used inside the loop callback.
func emitJSONRaw(out chan<- ServiceEvent, seq *atomic.Int64, t harnesses.EventType, meta map[string]string, payload any) {
	emitJSON(out, seq, t, meta, payload)
}

// finalizeAndEmit stamps the service-owned session-log path onto final,
// records the terminal session.end event, and forwards the final to the
// public event stream. Every terminal emit path in runExecute funnels
// through this helper so the session log and the event channel stay in
// lock-step (CONTRACT-003).
//
// finalizeAndEmit also performs the CONTRACT-003 echo of top-level Role
// and CorrelationID into the final event Metadata (top-level wins over
// any caller-supplied Metadata entry under the same reserved key) and
// stamps RoutingActual.Power from the catalog projection of the
// actually-dispatched Model. When the caller set both top-level
// Role/CorrelationID and the same reserved Metadata key, a
// MetadataKeyCollision warning is appended to final.Warnings.
func finalizeAndEmit(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, req ServiceExecuteRequest, sl *serviceSessionLog, final harnesses.FinalData) {
	if sl != nil && sl.path != "" {
		final.SessionLogPath = sl.path
	}
	// Stamp catalog power onto the actually-dispatched RoutingActual.
	// final.RoutingActual is set by the caller (one per terminal path);
	// when nil we leave it nil to avoid synthesizing routing evidence.
	if final.RoutingActual != nil && final.RoutingActual.Power == 0 {
		final.RoutingActual.Power = catalogPowerForModel(serviceRoutingCatalog(), final.RoutingActual.Model)
	}
	// Detect reserved metadata-key collisions and append a warning so the
	// caller learns when their caller-supplied Metadata entries were
	// overridden by the top-level Role / CorrelationID fields.
	if collisions := metadataReservedKeyCollisions(req.Metadata, req.Role, req.CorrelationID); len(collisions) > 0 {
		final.Warnings = append(final.Warnings, harnesses.FinalWarning{
			Code:    MetadataWarningCodeKeyCollision,
			Message: metadataKeyCollisionMessage(collisions),
		})
	}
	// Echo Role + CorrelationID onto the final event Metadata.
	finalMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
	if sl != nil {
		if ovr := sl.override; ovr != nil && !ovr.emitted.Load() {
			sl.writeOverrideEvent(ServiceEventTypeOverride, ovr.payload)
		}
		sl.writeEnd(req, finalMeta, final)
	}
	emitFinal(out, seq, finalMeta, final)
}

package openai

import (
	"context"
	"errors"
	"fmt"
	"net"
	"strings"
)

// ErrEndpointUnreachable is the sentinel callers match via errors.Is when
// distinguishing "this endpoint is down / unreachable" from everything else.
// Wrapped by ReachabilityError.
var ErrEndpointUnreachable = errors.New("openai: endpoint unreachable")

// ReachabilityError describes a failure attributable to the endpoint being
// unreachable or returning a server-side 5xx — distinct from request-level
// client errors (4xx) or model-specific errors. Callers use errors.Is(err,
// ErrEndpointUnreachable) to detect it.
type ReachabilityError struct {
	// Endpoint is the base URL of the provider that failed.
	Endpoint string
	// Operation identifies what was being attempted when the failure
	// occurred. Typical values: "probe_models", "chat_completions".
	Operation string
	// StatusCode is the HTTP status code if the failure was HTTP-level;
	// 0 for non-HTTP failures (dial error, timeout, TLS handshake, etc.).
	StatusCode int
	// Cause is the underlying error.
	Cause error
}

func (e *ReachabilityError) Error() string {
	if e == nil {
		return ""
	}
	endpoint := e.Endpoint
	if endpoint == "" {
		endpoint = "<unknown>"
	}
	op := e.Operation
	if op == "" {
		op = "request"
	}
	if e.StatusCode > 0 {
		return fmt.Sprintf("openai: endpoint unreachable (%s %s: HTTP %d): %v", endpoint, op, e.StatusCode, e.Cause)
	}
	return fmt.Sprintf("openai: endpoint unreachable (%s %s): %v", endpoint, op, e.Cause)
}

// Unwrap returns the underlying cause so errors.As / errors.Unwrap traverse
// through the reachability wrapper.
func (e *ReachabilityError) Unwrap() error { return e.Cause }

// Is reports whether target is ErrEndpointUnreachable. This makes
// errors.Is(err, openai.ErrEndpointUnreachable) return true for any
// *ReachabilityError regardless of the underlying cause.
func (e *ReachabilityError) Is(target error) bool {
	return target == ErrEndpointUnreachable
}

// newReachabilityError wraps cause as a ReachabilityError. Returns nil
// unchanged when cause is nil. Exported via the helper functions below.
func newReachabilityError(endpoint, operation string, statusCode int, cause error) *ReachabilityError {
	if cause == nil {
		return nil
	}
	return &ReachabilityError{
		Endpoint:   endpoint,
		Operation:  operation,
		StatusCode: statusCode,
		Cause:      cause,
	}
}

// ClassifyHTTPStatus returns a ReachabilityError when the status code is
// server-side (5xx); nil otherwise. Callers combine with ClassifyNetwork for
// the full picture.
func ClassifyHTTPStatus(endpoint, operation string, statusCode int, body string) error {
	if statusCode >= 500 {
		return newReachabilityError(endpoint, operation, statusCode,
			fmt.Errorf("HTTP %d: %s", statusCode, strings.TrimSpace(body)))
	}
	return nil
}

// ClassifyNetwork wraps a transport-level error as a ReachabilityError when
// it looks like the endpoint was unreachable — connection refused, dial
// timeouts, TLS handshake failure, DNS resolution failure, mid-response reset.
// Context cancellation and context-deadline-exceeded are NOT wrapped — those
// are the caller's own deadline and should bubble as the caller's concern.
// Returns nil when cause is nil.
func ClassifyNetwork(endpoint, operation string, cause error) error {
	if cause == nil {
		return nil
	}
	if errors.Is(cause, context.Canceled) || errors.Is(cause, context.DeadlineExceeded) {
		// Caller's own context; bubble as-is.
		return cause
	}
	var netErr net.Error
	if errors.As(cause, &netErr) {
		return newReachabilityError(endpoint, operation, 0, cause)
	}
	// String-sniff for the common cases that don't surface a net.Error
	// interface — e.g. http transport errors wrapping dial failures.
	msg := cause.Error()
	markers := []string{
		"connection refused",
		"connection reset",
		"broken pipe",
		"no such host",
		"TLS handshake",
		"tls: handshake",
		"EOF",
		"i/o timeout",
	}
	for _, m := range markers {
		if strings.Contains(msg, m) {
			return newReachabilityError(endpoint, operation, 0, cause)
		}
	}
	return cause
}

// Model-family error codes observed on /v1/chat/completions 404 responses.
// A generic 404 (no body code) is likely a wrong base URL / path and should
// NOT failover; a model-not-found 404 is endpoint-says-yes-to-url but
// no-to-this-model and SHOULD failover.
var modelNotFoundCodes = []string{
	"model_not_found",
	"model_not_supported",
	"invalid_model",
	"not_found",
}

// IsModelNotFound returns true when the response body from a 404 on
// /v1/chat/completions contains a model-specific error code. Caller decides
// whether to failover based on this + the pinned flag.
func IsModelNotFound(body string) bool {
	lowered := strings.ToLower(body)
	for _, code := range modelNotFoundCodes {
		if strings.Contains(lowered, code) {
			return true
		}
	}
	return false
}

// ShouldFailover returns true iff err warrants trying the next routing
// candidate instead of bubbling up. Returns false when:
//   - the request is pinned (operator explicitly chose a provider)
//   - the error is a caller-level concern (context.Canceled /
//     context.DeadlineExceeded)
//   - the error is a request-validation error the next endpoint can't fix
//     (400 Bad Request, generic 404 likely indicating wrong URL)
//
// Returns true for:
//   - ReachabilityError (5xx, dial failures, TLS, network resets)
//   - 401 / 403 auth failures (another endpoint might have valid auth)
//   - 404 responses whose body indicates the model specifically isn't
//     served (IsModelNotFound)
//   - 429 rate-limit / quota errors
//
// pinned should be req.Provider != "" captured BEFORE the failover loop.
func ShouldFailover(err error, pinned bool) bool {
	if err == nil {
		return false
	}
	if pinned {
		return false
	}
	if errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded) {
		return false
	}
	if errors.Is(err, ErrEndpointUnreachable) {
		return true
	}
	var httpErr *HTTPStatusError
	if errors.As(err, &httpErr) {
		switch {
		case httpErr.StatusCode == 400:
			return false
		case httpErr.StatusCode == 401, httpErr.StatusCode == 403:
			return true
		case httpErr.StatusCode == 404:
			return IsModelNotFound(httpErr.Body)
		case httpErr.StatusCode == 429:
			return true
		case httpErr.StatusCode >= 500:
			return true
		}
	}
	return false
}

// HTTPStatusError is a typed client-level HTTP error that carries the status
// code and response body so ShouldFailover can classify beyond
// ReachabilityError (which is only for 5xx / network). Callers that surface
// 4xx errors from openai-compatible servers should wrap them as
// HTTPStatusError to participate in the failover policy.
type HTTPStatusError struct {
	Endpoint   string
	Operation  string
	StatusCode int
	Body       string
}

func (e *HTTPStatusError) Error() string {
	if e == nil {
		return ""
	}
	op := e.Operation
	if op == "" {
		op = "request"
	}
	return fmt.Sprintf("openai: %s %s returned HTTP %d: %s", e.Endpoint, op, e.StatusCode, strings.TrimSpace(e.Body))
}

package fizeau

import (
	"context"
	"errors"
	"fmt"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/easel/fizeau/internal/provider/openai"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// stubClock is a deterministic time source for tests.
type stubClock struct {
	mu  sync.Mutex
	now time.Time
}

func newStubClock() *stubClock {
	return &stubClock{now: time.Date(2026, 4, 21, 12, 0, 0, 0, time.UTC)}
}

func (c *stubClock) Now() time.Time {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.now
}

func (c *stubClock) advance(d time.Duration) {
	c.mu.Lock()
	c.now = c.now.Add(d)
	c.mu.Unlock()
}

func testCache(clock *stubClock) *catalogCache {
	return newCatalogCache(catalogCacheOptions{
		FreshTTL:            10 * time.Second,
		StaleTTL:            60 * time.Second,
		UnreachableCooldown: 5 * time.Second,
		UnreachableJitter:   0, // deterministic tests
		Now:                 clock.Now,
		RandInt63n:          func(n int64) int64 { return 0 },
	})
}

func testKey(baseURL string) catalogCacheKey {
	return newCatalogCacheKey(baseURL, "apikey", map[string]string{"X-Test": "yes"})
}

func TestCatalogCache_FreshHitAvoidsNetwork(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	var callCount atomic.Int32
	probe := func(ctx context.Context) ([]string, error) {
		callCount.Add(1)
		return []string{"model-a", "model-b"}, nil
	}

	// Cold miss → synchronous probe.
	r1, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	assert.Equal(t, []string{"model-a", "model-b"}, r1.IDs)
	assert.False(t, r1.FromCache, "cold miss is not from cache")
	assert.EqualValues(t, 1, callCount.Load())

	// Fresh hit within FreshTTL → no probe.
	clock.advance(5 * time.Second)
	r2, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	assert.Equal(t, []string{"model-a", "model-b"}, r2.IDs)
	assert.True(t, r2.FromCache)
	assert.False(t, r2.Stale)
	assert.EqualValues(t, 1, callCount.Load(), "fresh hit must not re-probe")
}

func TestCatalogCache_StaleServesCachedAndAsyncRefreshes(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	var callCount atomic.Int32
	refreshedCh := make(chan struct{}, 2)
	probe := func(ctx context.Context) ([]string, error) {
		n := callCount.Add(1)
		if n > 1 {
			refreshedCh <- struct{}{}
		}
		return []string{"fresh-model"}, nil
	}

	// Seed the cache.
	_, _ = cache.Get(context.Background(), key, probe)

	// Advance past FreshTTL but within StaleTTL.
	clock.advance(20 * time.Second)

	// Stale Get returns cached + kicks async refresh.
	r, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	assert.True(t, r.FromCache)
	assert.True(t, r.Stale, "result must be flagged stale")
	assert.Equal(t, []string{"fresh-model"}, r.IDs)

	// Wait for async refresh to complete.
	select {
	case <-refreshedCh:
		// refreshed
	case <-time.After(2 * time.Second):
		t.Fatal("async refresh did not fire within 2s")
	}

	// After refresh, the next call should see the fresh fetch timestamp.
	r2, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	assert.True(t, r2.FromCache, "still within FreshTTL of the refresh")
}

func TestCatalogCache_AsyncRefreshUsesConfiguredDeadline(t *testing.T) {
	clock := newStubClock()
	cache := newCatalogCache(catalogCacheOptions{
		FreshTTL:            10 * time.Second,
		StaleTTL:            60 * time.Second,
		UnreachableCooldown: 5 * time.Second,
		UnreachableJitter:   0,
		AsyncRefreshTimeout: 40 * time.Millisecond,
		Now:                 clock.Now,
		RandInt63n:          func(n int64) int64 { return 0 },
	})
	key := testKey("http://host/v1")

	var callCount atomic.Int32
	deadlineCh := make(chan time.Duration, 1)
	doneCh := make(chan error, 1)
	probe := func(ctx context.Context) ([]string, error) {
		callCount.Add(1)
		deadline, ok := ctx.Deadline()
		if !ok {
			deadlineCh <- -1
			doneCh <- context.Canceled
			return nil, context.Canceled
		}
		deadlineCh <- time.Until(deadline)
		<-ctx.Done()
		err := ctx.Err()
		doneCh <- err
		return nil, err
	}

	// Seed the cache so the next call is stale and triggers async refresh.
	_, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
		return []string{"seed-model"}, nil
	})
	require.NoError(t, err)
	clock.advance(20 * time.Second)

	r, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	assert.True(t, r.Stale)
	assert.True(t, r.FromCache)

	select {
	case remaining := <-deadlineCh:
		assert.Greater(t, remaining, time.Duration(0), "refresh context must have a live deadline")
		assert.LessOrEqual(t, remaining, 40*time.Millisecond, "refresh deadline must respect the configured timeout")
	case <-time.After(1 * time.Second):
		t.Fatal("async refresh probe did not start")
	}

	select {
	case err := <-doneCh:
		require.ErrorIs(t, err, context.DeadlineExceeded)
	case <-time.After(1 * time.Second):
		t.Fatal("async refresh probe did not observe cancellation")
	}

	assert.EqualValues(t, 1, callCount.Load(), "one async refresh probe should run under the configured deadline")
}

func TestCatalogCache_ColdMissCoalesces(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	var inflight atomic.Int32
	var maxConcurrent atomic.Int32
	gate := make(chan struct{})
	probe := func(ctx context.Context) ([]string, error) {
		n := inflight.Add(1)
		// Track the peak concurrent probes so we can assert coalescing.
		for {
			peak := maxConcurrent.Load()
			if n <= peak || maxConcurrent.CompareAndSwap(peak, n) {
				break
			}
		}
		<-gate
		inflight.Add(-1)
		return []string{"coalesced-model"}, nil
	}

	const N = 10
	var wg sync.WaitGroup
	var started sync.WaitGroup
	wg.Add(N)
	started.Add(N)

	for i := 0; i < N; i++ {
		go func() {
			defer wg.Done()
			started.Done()
			_, _ = cache.Get(context.Background(), key, probe)
		}()
	}
	started.Wait()
	// Give all goroutines a moment to reach the singleflight point.
	time.Sleep(50 * time.Millisecond)
	close(gate)
	wg.Wait()

	assert.EqualValues(t, 1, maxConcurrent.Load(),
		"singleflight must coalesce N concurrent cold-miss callers into 1 probe")
}

func TestCatalogCache_ReachabilityErrorCooldown(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	var callCount atomic.Int32
	reachErr := &openai.ReachabilityError{
		Endpoint: "http://host/v1", Operation: "probe_models", StatusCode: 502,
		Cause: errors.New("bad gateway"),
	}
	probe := func(ctx context.Context) ([]string, error) {
		callCount.Add(1)
		return nil, reachErr
	}

	// First probe fails with ReachabilityError.
	_, err := cache.Get(context.Background(), key, probe)
	require.Error(t, err)
	assert.True(t, errors.Is(err, openai.ErrEndpointUnreachable))
	assert.EqualValues(t, 1, callCount.Load())

	// Within cooldown window, cache returns the same error without re-probing.
	clock.advance(2 * time.Second)
	_, err = cache.Get(context.Background(), key, probe)
	require.Error(t, err)
	assert.True(t, errors.Is(err, openai.ErrEndpointUnreachable))
	assert.EqualValues(t, 1, callCount.Load(), "must not re-probe within cooldown")

	// Past cooldown, re-probe.
	clock.advance(10 * time.Second)
	_, _ = cache.Get(context.Background(), key, probe)
	assert.EqualValues(t, 2, callCount.Load(), "must re-probe after cooldown expires")
}

func TestCatalogCache_DiscoveryUnsupportedFallsBackToPassthrough(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	var callCount atomic.Int32
	probe := func(ctx context.Context) ([]string, error) {
		callCount.Add(1)
		return nil, ErrDiscoveryUnsupported()
	}

	r, err := cache.Get(context.Background(), key, probe)
	require.Error(t, err) // discovery-unsupported is surfaced as err
	assert.False(t, r.DiscoverySupported,
		"endpoint marked as discovery-unsupported")
	assert.Empty(t, r.IDs)
	assert.EqualValues(t, 1, callCount.Load())

	// Fresh cache state suppresses re-probes within FreshTTL even when
	// last state was DiscoverySupported=false. Note: because LastErr != nil
	// on the entry, the "fresh" branch doesn't short-circuit; this is by
	// design — the caller wants to know discovery remains unsupported on
	// every call. Verify the cache does NOT re-probe within cooldown.
	// (Discovery-unsupported is not a ReachabilityError → no cooldown set.)
	// The cache re-probes — that's acceptable because /v1/models 404 is
	// cheap, and in practice we expect this to be rare (most servers
	// support discovery).
}

func TestCatalogCache_SnapshotsDontAliasCacheState(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")
	probe := func(ctx context.Context) ([]string, error) {
		return []string{"model-x", "model-y"}, nil
	}
	r, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)

	// Mutate caller's slice; cache state must be unaffected.
	r.IDs[0] = "mutated"

	r2, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	assert.Equal(t, []string{"model-x", "model-y"}, r2.IDs,
		"caller mutation must not leak into cache state")
}

func TestCatalogCacheKey_String(t *testing.T) {
	k1 := newCatalogCacheKey("http://host/v1", "key1", nil)
	k2 := newCatalogCacheKey("http://host/v1", "key2", nil)
	k3 := newCatalogCacheKey("http://host/v1", "key1", map[string]string{"X-Custom": "a"})
	k4 := newCatalogCacheKey("http://host/v1", "key1", map[string]string{"X-Custom": "b"})

	assert.NotEqual(t, k1.String(), k2.String(), "different API keys must hash differently")
	assert.NotEqual(t, k1.String(), k3.String(), "adding headers must change the key")
	assert.NotEqual(t, k3.String(), k4.String(), "header values must be part of the hash")
	assert.Equal(t, k1.String(), k1.String(), "same inputs produce same key")
}

func TestHashHeaders_OrderIndependent(t *testing.T) {
	a := map[string]string{"X-One": "1", "X-Two": "2"}
	b := map[string]string{"X-Two": "2", "X-One": "1"}
	assert.Equal(t, hashHeaders(a), hashHeaders(b),
		"header hash must be independent of Go map iteration order")
}

func TestNewCatalogCacheKey_EmptyHeadersHashZero(t *testing.T) {
	k1 := newCatalogCacheKey("url", "key", nil)
	k2 := newCatalogCacheKey("url", "key", map[string]string{})
	assert.Equal(t, k1, k2, "nil and empty headers must produce identical keys")
}

// Ensure helper functions don't cause data races under concurrent Get calls.
func TestCatalogCache_RaceSafety(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	probe := func(ctx context.Context) ([]string, error) {
		return []string{"m1", "m2"}, nil
	}

	const N = 50
	var wg sync.WaitGroup
	wg.Add(N)
	for i := 0; i < N; i++ {
		go func(i int) {
			defer wg.Done()
			key := testKey(fmt.Sprintf("http://host-%d/v1", i%5))
			_, _ = cache.Get(context.Background(), key, probe)
		}(i)
	}
	wg.Wait()
}

