			reasoningContent := extractReasoningContent(chunk.RawJSON())
			if reasoningContent != "" {
				aggReasoningContent.WriteString(reasoningContent)
			}

			if len(chunk.Choices) > 0 {
				choice := chunk.Choices[0]

				for _, tc := range choice.Delta.ToolCalls {
					id := tc.ID
					if id != "" {
						indexToID[int(tc.Index)] = id
					} else {
						id = indexToID[int(tc.Index)]
					}
					send(agent.StreamDelta{
						Model:        chunk.Model,
						ToolCallID:   id,
						ToolCallName: tc.Function.Name,
						ToolCallArgs: tc.Function.Arguments,
					})
				}

				if choice.Delta.Content != "" || choice.FinishReason != "" || reasoningContent != "" {
					send(agent.StreamDelta{
						Model:            chunk.Model,
						Content:          choice.Delta.Content,
						ReasoningContent: reasoningContent,
						FinishReason:     string(choice.FinishReason),
					})
				} else if len(choice.Delta.ToolCalls) == 0 {
					send(agent.StreamDelta{
						Model:        chunk.Model,
						FinishReason: string(choice.FinishReason),
					})
				}
			} else {
				send(agent.StreamDelta{Model: chunk.Model})
			}

			if chunk.Usage.TotalTokens != 0 {
				usage := tokenUsage(
					int(chunk.Usage.PromptTokens),
					int(chunk.Usage.CompletionTokens),
					int(chunk.Usage.TotalTokens),
					int(chunk.Usage.PromptTokensDetails.CachedTokens),
				)
				usage.Reasoning, usage.ReasoningTokensApprox = extractReasoningTokens(chunk.Usage.RawJSON(), aggReasoningContent.String())
				send(agent.StreamDelta{Usage: &usage})
			}
		}

		if err := stream.Err(); err != nil {
			send(agent.StreamDelta{Err: classifyStreamErr(err)})
			return
		}

		done := agent.StreamDelta{
			Model: responseModel,
			Done:  true,
		}
		if hooks.Attempt != nil {
			done.Attempt = hooks.Attempt(responseModel, streamCost)
		}
		send(done)
	}()

	return ch, nil
}

func buildParams(model string, messages []agent.Message, tools []agent.ToolDef, opts RequestOptions) oai.ChatCompletionNewParams {
	params := oai.ChatCompletionNewParams{
		Model:    model,
		Messages: convertMessages(messages),
	}
	if len(tools) > 0 {
		params.Tools = convertTools(tools)
	}
	if opts.MaxTokens > 0 {
		params.MaxTokens = oai.Int(int64(opts.MaxTokens))
	}
	if opts.Temperature != nil {
		params.Temperature = oai.Float(*opts.Temperature)
	}
	if opts.TopP != nil {
		params.TopP = oai.Float(*opts.TopP)
	}
	if opts.Seed != 0 {
		params.Seed = oai.Int(opts.Seed)
	}
	if len(opts.Stop) > 0 {
		params.Stop = oai.ChatCompletionNewParamsStopUnion{OfStringArray: opts.Stop}
	}
	return params
}

func convertMessages(msgs []agent.Message) []oai.ChatCompletionMessageParamUnion {
	var result []oai.ChatCompletionMessageParamUnion
	for _, m := range msgs {
		switch m.Role {
		case agent.RoleSystem:
			result = append(result, oai.SystemMessage(m.Content))
		case agent.RoleUser:
			result = append(result, oai.UserMessage(m.Content))
		case agent.RoleAssistant:
			if len(m.ToolCalls) > 0 {
				var toolCalls []oai.ChatCompletionMessageToolCallParam
				for _, tc := range m.ToolCalls {
					toolCalls = append(toolCalls, oai.ChatCompletionMessageToolCallParam{
						ID: tc.ID,
						Function: oai.ChatCompletionMessageToolCallFunctionParam{
							Name:      tc.Name,
							Arguments: string(tc.Arguments),
						},
					})
				}
				assistant := oai.ChatCompletionAssistantMessageParam{
					Content: oai.ChatCompletionAssistantMessageParamContentUnion{
						OfString: param.NewOpt(m.Content),
					},
					ToolCalls: toolCalls,
				}
				result = append(result, oai.ChatCompletionMessageParamUnion{OfAssistant: &assistant})
			} else {
				result = append(result, oai.AssistantMessage(m.Content))
			}
		case agent.RoleTool:
			result = append(result, oai.ToolMessage(m.Content, m.ToolCallID))
		}
	}
	return result
}

func convertTools(tools []agent.ToolDef) []oai.ChatCompletionToolParam {
	var result []oai.ChatCompletionToolParam
	for _, t := range tools {
		var params map[string]interface{}
		_ = json.Unmarshal(t.Parameters, &params)

		result = append(result, oai.ChatCompletionToolParam{
			Function: oai.FunctionDefinitionParam{
				Name:        t.Name,
				Description: oai.String(t.Description),
				Parameters:  oai.FunctionParameters(params),
			},
		})
	}
	return result
}

func extractToolCalls(calls []oai.ChatCompletionMessageToolCall) []agent.ToolCall {
	if len(calls) == 0 {
		return nil
	}
	var result []agent.ToolCall
	for _, c := range calls {
		result = append(result, agent.ToolCall{
			ID:        c.ID,
			Name:      c.Function.Name,
			Arguments: json.RawMessage(c.Function.Arguments),
		})
	}
	return result
}

func extractReasoningContent(rawJSON string) string {
	if rawJSON == "" {
		return ""
	}
	var raw struct {
		Choices []struct {
			Delta struct {
				ReasoningContent string `json:"reasoning_content"`
			} `json:"delta"`
		} `json:"choices"`
	}
	if err := json.Unmarshal([]byte(rawJSON), &raw); err != nil || len(raw.Choices) == 0 {
		return ""
	}
	return raw.Choices[0].Delta.ReasoningContent
}

func tokenUsage(input, output, total, cacheRead int) agent.TokenUsage {
	usage := agent.TokenUsage{
		Input:  input,
		Output: output,
		Total:  total,
	}
	if cacheRead > 0 {
		usage.CacheRead = cacheRead
	}
	return usage
}

// extractReasoningTokens resolves the reasoning token count per ADR-010
// Amendment §8. Resolution chain:
//  1. usage.completion_tokens_details.reasoning_tokens (authoritative; even
//     an explicit zero is honoured — the provider signalled no reasoning ran).
//  2. Top-level usage.reasoning_tokens > 0 (non-standard servers).
//  3. char-count(reasoningContent)÷4 when the usage path is absent AND
//     reasoningContent is non-empty. Returns approx=true.
//
// The char-count/4 estimator is a v1 placeholder (4 chars ≈ 1 token for
// English; accuracy degrades for CJK or heavily-symbolic content). A future
// bead can replace it with a real tokenizer once measurement shows the
// approximation error matters in practice.
//
// Returns (tokens, approx). approx is true only in case 3.
func extractReasoningTokens(rawUsageJSON, reasoningContent string) (int, bool) {
	if rawUsageJSON == "" {
		if reasoningContent != "" {
			return len(reasoningContent) / 4, true
		}
		return 0, false
	}
	var raw struct {
		CompletionTokensDetails struct {
			// Pointer so absent vs. explicit-zero are distinguishable: nil means
			// the field was not present; &0 means the server said "no reasoning".
			ReasoningTokens *int `json:"reasoning_tokens"`
		} `json:"completion_tokens_details"`
		// Some non-OpenAI servers put reasoning_tokens at the top level.
		ReasoningTokens *int `json:"reasoning_tokens,omitempty"`
	}
	if err := json.Unmarshal([]byte(rawUsageJSON), &raw); err != nil {
		return 0, false
	}
	if raw.CompletionTokensDetails.ReasoningTokens != nil {
		// Field present — respect the value even if zero (provider said no
		// reasoning ran; do not fall through to the char-count heuristic).
		return *raw.CompletionTokensDetails.ReasoningTokens, false
	}
	if raw.ReasoningTokens != nil && *raw.ReasoningTokens > 0 {
		return *raw.ReasoningTokens, false
	}
	// usage path absent; fall back to reasoning_content char-count estimate.
	if reasoningContent != "" {
		return len(reasoningContent) / 4, true
	}
	return 0, false
}

// extractMessageReasoningContent reads choices[0].message.reasoning_content
// from a full (non-streaming) Chat Completions response JSON. Providers that
// do thinking inline but do not populate completion_tokens_details (e.g. ds4)
// carry the thinking text here. Returns "" when absent or unparseable.
func extractMessageReasoningContent(rawCompletionJSON string) string {
	if rawCompletionJSON == "" {
		return ""
	}
	var raw struct {
		Choices []struct {
			Message struct {
				ReasoningContent string `json:"reasoning_content"`
			} `json:"message"`
		} `json:"choices"`
	}
	if err := json.Unmarshal([]byte(rawCompletionJSON), &raw); err != nil || len(raw.Choices) == 0 {
		return ""
	}
	return raw.Choices[0].Message.ReasoningContent
}

package fizeau

import (
	"context"
	"encoding/json"
	"go/ast"
	"go/parser"
	"go/token"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/easel/fizeau/internal/routing"
)

// TestServiceExecuteRequestNoPreResolved is an AST guard against the
// removed PreResolved field. ADR-005 step 1 deleted it; reintroducing it
// would silently re-enable caller-supplied route decisions.
func TestServiceExecuteRequestNoPreResolved(t *testing.T) {
	requireStructHasNoField(t, "service.go", "ServiceExecuteRequest", "PreResolved")
	requireStructHasNoField(t, "service.go", "RouteRequest", "PreResolved")
}

// TestServiceExecuteRequestHasAutoSelectionFields is an AST guard for the
// EstimatedPromptTokens / RequiresTools fields that ADR-005 step 1 added
// to ServiceExecuteRequest and RouteRequest.
func TestServiceExecuteRequestHasAutoSelectionFields(t *testing.T) {
	requireStructHasField(t, "service.go", "ServiceExecuteRequest", "EstimatedPromptTokens")
	requireStructHasField(t, "service.go", "ServiceExecuteRequest", "RequiresTools")
	requireStructHasField(t, "service.go", "RouteRequest", "EstimatedPromptTokens")
	requireStructHasField(t, "service.go", "RouteRequest", "RequiresTools")
}

func requireStructHasField(t *testing.T, file, structName, field string) {
	t.Helper()
	if structHasField(t, file, structName, field) {
		return
	}
	t.Fatalf("expected struct %s in %s to declare field %s", structName, file, field)
}

func requireStructHasNoField(t *testing.T, file, structName, field string) {
	t.Helper()
	if !structHasField(t, file, structName, field) {
		return
	}
	t.Fatalf("struct %s in %s must not declare field %s (ADR-005 step 1)", structName, file, field)
}

package routehealth

import (
	"fmt"
	"strings"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/routing"
)

// DefaultCooldown is the process-local route-attempt TTL used when service
// configuration does not provide a health cooldown.
const DefaultCooldown = 30 * time.Second

// Attempt records availability feedback for one routed attempt.
type Attempt struct {
	Harness   string
	Provider  string
	Model     string
	Endpoint  string
	Status    string
	Reason    string
	Error     string
	Duration  time.Duration
	Timestamp time.Time
}

// Key is the normalized route-attempt identity.
type Key struct {
	Harness  string
	Provider string
	Model    string
	Endpoint string
}

// Record is an active route-attempt failure.
type Record struct {
	Key        Key
	Status     string
	Reason     string
	Error      string
	Duration   time.Duration
	RecordedAt time.Time
}

type metricRecord struct {
	attempts      int
	successes     int
	totalDuration time.Duration
	recordedAt    time.Time
}

// Store owns process-local route-attempt failure feedback and reliability
// metrics. It is safe for concurrent use.
type Store struct {
	mu       sync.RWMutex
	failures map[Key]Record
	metrics  map[Key]metricRecord
}

// NewStore returns an empty route-health store.
func NewStore() *Store {
	return &Store{
		failures: make(map[Key]Record),
		metrics:  make(map[Key]metricRecord),
	}
}

// RecordAttempt records availability feedback. Success clears matching active
// failures; non-success records an active failure and updates metrics.
func (s *Store) RecordAttempt(attempt Attempt) error {
	key := NormalizeKey(attempt)
	if key.Harness == "" && key.Provider == "" {
		return fmt.Errorf("route attempt requires harness or provider")
	}
	status := strings.ToLower(strings.TrimSpace(attempt.Status))
	if status == "" {
		return fmt.Errorf("route attempt status is required")
	}
	recordedAt := attempt.Timestamp
	if recordedAt.IsZero() {
		recordedAt = time.Now()
	}
	recordedAt = recordedAt.UTC()

	s.mu.Lock()
	defer s.mu.Unlock()
	if s.failures == nil {
		s.failures = make(map[Key]Record)
	}
	if s.metrics == nil {
		s.metrics = make(map[Key]metricRecord)
	}
	s.recordMetricLocked(key, Succeeded(status), attempt.Duration, recordedAt)

	if Succeeded(status) {
		s.clearFailuresLocked(key)
		return nil
	}

	s.failures[key] = Record{
		Key:        key,
		Status:     status,
		Reason:     strings.TrimSpace(attempt.Reason),
		Error:      strings.TrimSpace(attempt.Error),
		Duration:   attempt.Duration,
		RecordedAt: recordedAt,
	}
	return nil
}

func (s *Store) recordMetricLocked(key Key, success bool, duration time.Duration, recordedAt time.Time) {
	record := s.metrics[key]
	record.attempts++
	if success {
		record.successes++
	}
	if duration > 0 {
		record.totalDuration += duration
	}
	record.recordedAt = recordedAt
	s.metrics[key] = record
}

// NormalizeKey returns the normalized route-attempt key for attempt.
func NormalizeKey(attempt Attempt) Key {
	return Key{
		Harness:  strings.TrimSpace(attempt.Harness),
		Provider: strings.TrimSpace(attempt.Provider),
		Model:    strings.TrimSpace(attempt.Model),
		Endpoint: strings.TrimSpace(attempt.Endpoint),
	}
}

// Succeeded reports whether status is a success spelling.
func Succeeded(status string) bool {
	switch status {
	case "success", "ok", "succeeded":
		return true
	default:
		return false
	}
}

func (s *Store) clearFailuresLocked(key Key) {
	for existing := range s.failures {
		if KeysMatch(existing, key) {
			delete(s.failures, existing)
		}
	}
}

// KeysMatch reports whether existing satisfies every non-empty query field.
func KeysMatch(existing, query Key) bool {
	if query.Harness != "" && existing.Harness != query.Harness {
		return false
	}
	if query.Provider != "" && existing.Provider != query.Provider {
		return false
	}
	if query.Model != "" && existing.Model != query.Model {
		return false
	}
	if query.Endpoint != "" && existing.Endpoint != query.Endpoint {
		return false
	}
	return true
}

// ActiveAttempts returns active failure records and removes expired records
// from the store.
func (s *Store) ActiveAttempts(now time.Time, ttl time.Duration) []Record {
	if s == nil {
		return nil
	}
	if ttl <= 0 {
		ttl = DefaultCooldown
	}
	if now.IsZero() {
		now = time.Now()
	}
	now = now.UTC()

	s.mu.Lock()
	defer s.mu.Unlock()
	if len(s.failures) == 0 {
		return nil
	}
	out := make([]Record, 0, len(s.failures))
	for key, record := range s.failures {
		if !record.RecordedAt.Add(ttl).After(now) {
			delete(s.failures, key)
			continue
		}
		out = append(out, record)
	}
	return out
}

// MetricSignals returns provider/model success-rate and latency maps suitable
// for routing inputs.
func (s *Store) MetricSignals(now time.Time, ttl time.Duration) (map[string]float64, map[string]float64) {
	if s == nil {
		return nil, nil
	}
	if ttl <= 0 {
		ttl = DefaultCooldown
	}
	if now.IsZero() {
		now = time.Now()
	}
	now = now.UTC()

	s.mu.RLock()
	defer s.mu.RUnlock()
	if len(s.metrics) == 0 {
		return nil, nil
	}
	successRate := make(map[string]float64, len(s.metrics))
	latencyMS := make(map[string]float64, len(s.metrics))
	for key, record := range s.metrics {
		if record.attempts <= 0 {
			continue
		}
		if !record.recordedAt.IsZero() && !record.recordedAt.Add(ttl).After(now) {
			continue
		}
		metricKey := ProviderModelKey(key)
		successRate[metricKey] = float64(record.successes) / float64(record.attempts)
		if record.totalDuration > 0 {
			latencyMS[metricKey] = float64(record.totalDuration.Milliseconds()) / float64(record.attempts)
		}
	}
	return successRate, latencyMS
}

// ProviderModelKey returns the routing provider/model metric key for key.
func ProviderModelKey(key Key) string {
	return routing.ProviderModelKey(key.Provider, key.Endpoint, key.Model)
}

