func routingPolicyForName(cat *modelcatalog.Catalog, name string) string {
	name = strings.TrimSpace(name)
	switch name {
	case "":
		return ""
	case "cheap", "default", "smart", "air-gapped":
		return name
	}
	if cat == nil {
		return name
	}
	_, policyName, ok := policyForName(cat, name)
	if !ok {
		return name
	}
	switch policyName {
	case "smart":
		return "smart"
	case "default":
		return "default"
	case "cheap":
		return "cheap"
	default:
		return policyName
	}
